function validateEmailPayload(body) {
  if (!body || typeof body !== "object") throw httpError(400, "Invalid payload");
  const { to, from, subject, text, html } = body;
  if (!to || !from || !subject) throw httpError(400, "Missing required fields: to, from, subject");
  if (!text && !html) throw httpError(400, "Provide at least one of: text, html");
}

async function sendSendGridEmail(body, env) {
  if (!env.SENDGRID_API_KEY) throw httpError(500, "Server misconfigured: SENDGRID_API_KEY missing");

  const payload = {
    personalizations: [{ to: [{ email: body.to }] }],
    from: { email: body.from },
    subject: body.subject,
    content: [],
  };

  if (body.text) payload.content.push({ type: "text/plain", value: body.text });
  if (body.html) payload.content.push({ type: "text/html", value: body.html });

  const resp = await fetch("https://api.sendgrid.com/v3/mail/send", {
    method: "POST",
    headers: {
      Authorization: `Bearer ${env.SENDGRID_API_KEY}`,
      "Content-Type": "application/json",
    },
    body: JSON.stringify(payload),
  });

  // SendGrid success is typically 202 with empty body
  if (!resp.ok) {
    const details = await safeReadText(resp);
    throw httpError(resp.status, "SendGrid API error", details || undefined);
  }

  return { status: resp.status };
}

